/**
 * Automerge sync compatibility test.
 *
 * Validates that the JS Automerge library (v2.2.x "next" API) can load and
 * sync documents produced by the Rust automerge 0.7 crate. The fixture bytes
 * are generated by the Rust test:
 *   cargo test -p runtimed -- notebook_doc::tests::export_fixture_bytes --nocapture
 *
 * Run with:
 *   cd apps/notebook && npx vitest run src/__tests__/automerge-compat.test.ts
 */

import { next as Automerge } from "@automerge/automerge";
import { describe, expect, it } from "vitest";

