interface CellDoc {
  id: string;
  cell_type: string;
  source: string;
  execution_count: string;
  outputs: string[];
}

interface NotebookSchema {
  notebook_id: string;
  cells: CellDoc[];
  metadata: { runtime: string; notebook_metadata: string };
}

/**
 * Run the Automerge sync protocol to completion between two peers.
 * Returns the final state of both docs and sync states.
 */
function syncPeers<T>(
  docA: Automerge.Doc<T>,
  syncA: Automerge.SyncState,
  docB: Automerge.Doc<T>,
  syncB: Automerge.SyncState,
  maxRounds = 10,
): {
  docA: Automerge.Doc<T>;
  syncA: Automerge.SyncState;
  docB: Automerge.Doc<T>;
  syncB: Automerge.SyncState;
} {
  for (let i = 0; i < maxRounds; i++) {
    // A → B
    const [newSyncA, msgA] = Automerge.generateSyncMessage(docA, syncA);
    syncA = newSyncA;
    if (msgA) {
      const [newDocB, newSyncB] = Automerge.receiveSyncMessage(
        docB,
        syncB,
        msgA,
      );
      docB = newDocB;
      syncB = newSyncB;
    }

    // B → A
    const [newSyncB2, msgB] = Automerge.generateSyncMessage(docB, syncB);
    syncB = newSyncB2;
    if (msgB) {
      const [newDocA, newSyncA2] = Automerge.receiveSyncMessage(
        docA,
        syncA,
        msgB,
      );
      docA = newDocA;
      syncA = newSyncA2;
    }

    // If neither side had anything to send, sync is complete
    if (!msgA && !msgB) break;
  }
  return { docA, syncA, docB, syncB };
}

describe("Automerge Rust ↔ JS compatibility", () => {
  it("can load Rust 0.7 doc bytes", () => {
    const doc = Automerge.load<NotebookSchema>(RUST_DOC_BYTES);
    // v2 next returns RawString for scalar strings; use String() to compare
    expect(String(doc.notebook_id)).toBe("compat-test");
    expect(doc.cells).toHaveLength(1);
    expect(String(doc.cells[0].id)).toBe("cell-1");
    expect(String(doc.cells[0].cell_type)).toBe("code");
    // Text CRDT fields read as plain strings
    expect(doc.cells[0].source).toBe("print('hello')");
    expect(String(doc.cells[0].execution_count)).toBe("1");
    expect(doc.cells[0].outputs).toHaveLength(0);
  });

  it("sync roundtrip preserves cell integrity", () => {
    const docA = Automerge.load<NotebookSchema>(RUST_DOC_BYTES);
    const docB = Automerge.load<NotebookSchema>(RUST_DOC_BYTES);

    const result = syncPeers(
      docA,
      Automerge.initSyncState(),
      docB,
      Automerge.initSyncState(),
    );

    // Both docs should still have the cell intact after sync
    expect(result.docA.cells).toHaveLength(1);
    expect(String(result.docA.cells[0].id)).toBe("cell-1");
    expect(result.docA.cells[0].source).toBe("print('hello')");

    expect(result.docB.cells).toHaveLength(1);
    expect(String(result.docB.cells[0].id)).toBe("cell-1");
    expect(result.docB.cells[0].source).toBe("print('hello')");
  });

  it("local change + sync preserves both docs", () => {
    // Frontend doc
    let feDoc = Automerge.load<NotebookSchema>(RUST_DOC_BYTES);

    // Make a local change (edit cell source)
    feDoc = Automerge.change(feDoc, (d) => {
      Automerge.updateText(d, ["cells", 0, "source"], "print('world')");
    });

    expect(feDoc.cells[0].source).toBe("print('world')");

    // Sync with peer loaded from same bytes
    const peerDoc = Automerge.load<NotebookSchema>(RUST_DOC_BYTES);

    const result = syncPeers(
      feDoc,
      Automerge.initSyncState(),
      peerDoc,
      Automerge.initSyncState(),
    );

    // Both should have the updated source
    expect(result.docA.cells[0].source).toBe("print('world')");
    expect(result.docB.cells[0].source).toBe("print('world')");

    // Other fields should be preserved
    expect(String(result.docB.cells[0].id)).toBe("cell-1");
    expect(String(result.docB.cells[0].cell_type)).toBe("code");
  });
});
